]],"expected":2}],"constraints":[{"zh":"网格为空或为矩形。","en":"The grid is empty or rectangular."}],"hints":{"zh":["每遇到一个未访问的 1，就发现了新岛屿。","从该格遍历并标记整个连通区域。","扫描网格；对新陆地计数并用 BFS/DFS 扩展四邻域。"],"en":["Every unvisited 1 starts a new island.","Traverse and mark the whole connected region.","Scan the grid; count new land and expand four neighbors with BFS/DFS."]},"reviewPoints":[{"zh":"连通分量计数由外层扫描触发。","en":"The outer scan starts each component count."},{"zh":"访问标记避免重复计数。","en":"Visited marking prevents duplicate counts."}],"estimatedMinutes":22},{"id":"ac-023","slug":"nearest-zero-distance","title":{"zh":"到最近零的距离","en":"Distance to the Nearest Zero"},"description":{"zh":"0/1 矩形网格至少包含一个 0，返回每个格到最近 0 的上下左右距离。","en":"A rectangular 0/1 grid contains at least one 0; return each cell distance to its nearest 0."},"difficulty":"medium","topics":["bfs"],"entryPoint":"nearestZeroDistance","templates":{"javascript":"function nearestZeroDistance(grid) {\n  // TODO: implement your solution.\n  \n}","python":"def nearest_zero_distance(grid):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-023-test-1","args":[[[0,0,0],[0,1,0],[1,1,1]]],"expected":[[0,0,0],[0,1,0],[1,2,1]],"isSample":true},{"id":"ac-023-test-2","args":[[[0]]],"expected":[[0]],"isSample":true},{"id":"ac-023-test-3","args":[[[1,0]]],"expected":[[1,0]],"isSample":false},{"id":"ac-023-test-4","args":[[[0,1],[1,1]]],"expected":[[0,1],[1,2]],"isSample":false}],"examples":[{"id":"ac-023-example","input":[[0,0,0],[0,1,0],[1,1,1]],"expected":[[0,0,0],[0,1,0],[1,2,1]]}],"constraints":[{"zh":"网格非空且至少有一个 0。","en":"The grid is non-empty and contains at least one 0."}],"hints":{"zh":["如果从每个 1 单独搜索会重复很多工作。","把所有 0 同时作为 BFS 起点。","零距离入队；首次访问邻格时距离加一。"],"en":["Searching separately from every 1 repeats much work.","Use every 0 as a simultaneous BFS source.","Enqueue zeros at distance zero; first visits get parent distance plus one."]},"reviewPoints":[{"zh":"多源 BFS 等价于加入一个虚拟共同起点。","en":"Multi-source BFS is equivalent to one virtual common source."},{"zh":"首次到达即为最短距离。","en":"The first arrival is the shortest distance."}],"estimatedMinutes":25},{"id":"ac-024","slug":"undirected-component-count","title":{"zh":"无向图连通分量","en":"Undirected Component Count"},"description":{"zh":"给定 n 个节点和无向边，返回图中的连通分量数量。","en":"Given n nodes and undirected edges, return the number of connected components."},"difficulty":"medium","topics":["dfs","bfs"],"entryPoint":"componentCount","templates":{"javascript":"function componentCount(n, edges) {\n  // TODO: implement your solution.\n  \n}","python":"def component_count(n, edges):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-024-test-1","args":[5,[[0,1],[1,2],[3,4]]],"expected":2,"isSample":true},{"id":"ac-024-test-2","args":[3,[]],"expected":3,"isSample":true},{"id":"ac-024-test-3","args":[1,[]],"expected":1,"isSample":false},{"id":"ac-024-test-4","args":[4,[[0,1],[1,2],[2,3]]],"expected":1,"isSample":false}],"examples":[{"id":"ac-024-example","input":[5,[[0,1],[1,2],[3,4]]],"expected":2}],"constraints":[{"zh":"0 <= 节点编号 < n。","en":"Node ids satisfy 0 <= id < n."}],"hints":{"zh":["每次从未访问节点开始会发现一个分量。","无向边要加入两个方向。","构建邻接表，外层扫描并对未访问节点执行 BFS/DFS。"],"en":["Starting from each unvisited node discovers one component.","Add each undirected edge in both directions.","Build adjacency lists, scan nodes, and BFS/DFS each unvisited one."]},"reviewPoints":[{"zh":"孤立节点也是一个分量。","en":"An isolated node is also a component."},{"zh":"遍历次数等于分量数。","en":"The number of traversal starts equals the component count."}],"estimatedMinutes":20},{"id":"ac-025","slug":"directed-reachable-count","title":{"zh":"有向图可达节点数","en":"Directed Reachable Node Count"},"description":{"zh":"给定有向边和起点，返回从起点可到达的不同节点数量，包含起点。","en":"Given directed edges and a start node, return the number of distinct reachable nodes including the start."},"difficulty":"easy","topics":["dfs","bfs"],"entryPoint":"reachableCount","templates":{"javascript":"function reachableCount(n, edges, start) {\n  // TODO: implement your solution.\n  \n}","python":"def reachable_count(n, edges, start):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-025-test-1","args":[5,[[0,1],[1,2],[3,4]],0],"expected":3,"isSample":true},{"id":"ac-025-test-2","args":[5,[[0,1],[1,2],[3,4]],3],"expected":2,"isSample":true},{"id":"ac-025-test-3","args":[1,[],0],"expected":1,"isSample":false},{"id":"ac-025-test-4","args":[3,[[0,1],[1,2],[2,0]],1],"expected":3,"isSample":false}],"examples":[{"id":"ac-025-example","input":[5,[[0,1],[1,2],[3,4]],0],"expected":3}],"constraints":[{"zh":"起点与边端点均为有效节点。","en":"The start and all edge endpoints are valid nodes."}],"hints":{"zh":["只沿边的给定方向扩展。","访问集合同时负责去重和防环。","从 start BFS/DFS，最终返回 visited 大小。"],"en":["Follow edges only in their given direction.","A visited set both deduplicates and prevents cycles.","BFS/DFS from start and return the visited-set size."]},"reviewPoints":[{"zh":"可达性与无向连通性不同。","en":"Directed reachability differs from undirected connectivity."},{"zh":"起点本身始终可达。","en":"The start node is always reachable."}],"estimatedMinutes":18},{"id":"ac-026","slug":"course-order-possible","title":{"zh":"课程是否可全部完成","en":"Can All Courses Be Completed"},"description":{"zh":"边 [course, prerequisite] 表示先修关系，判断是否能完成全部 n 门课程。","en":"An edge [course, prerequisite] is a prerequisite relation; determine whether all n courses can be completed."},"difficulty":"medium","topics":["dfs"],"entryPoint":"canFinishCourses","templates":{"javascript":"function canFinishCourses(n, prerequisites) {\n  // TODO: implement your solution.\n  \n}","python":"def can_finish_courses(n, prerequisites):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-026-test-1","args":[2,[[1,0]]],"expected":true,"isSample":true},{"id":"ac-026-test-2","args":[2,[[1,0],[0,1]]],"expected":false,"isSample":true},{"id":"ac-026-test-3","args":[1,[]],"expected":true,"isSample":false},{"id":"ac-026-test-4","args":[1,[[0,0]]],"expected":false,"isSample":false}],"examples":[{"id":"ac-026-example","input":[2,[[1,0]]],"expected":true}],"constraints":[{"zh":"0 <= 课程编号 < n。","en":"Course ids satisfy 0 <= id < n."}],"hints":{"zh":["无法完成的根本原因是什么图结构？","可以检测有向环，也可以逐步移除入度为 0 的节点。","拓扑法：统计入度，队列处理零入度并减少后继入度。"],"en":["What graph structure makes completion impossible?","Detect a directed cycle or repeatedly remove indegree-zero nodes.","Topological method: queue zero-indegree nodes and reduce successors."]},"reviewPoints":[{"zh":"DAG 才存在完整拓扑顺序。","en":"Only a DAG has a complete topological order."},{"zh":"处理节点数不足 n 说明存在环。","en":"Processing fewer than n nodes reveals a cycle."}],"estimatedMinutes":22},{"id":"ac-027","slug":"subarray-target-count","title":{"zh":"目标和子数组数量","en":"Count Target-Sum Subarrays"},"description":{"zh":"返回整数数组中元素和恰好等于 target 的连续子数组数量。","en":"Return the number of contiguous subarrays whose sum equals target."},"difficulty":"medium","topics":["array-hash"],"entryPoint":"countTargetSubarrays","templates":{"javascript":"function countTargetSubarrays(values, target) {\n  // TODO: implement your solution.\n  \n}","python":"def count_target_subarrays(values, target):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-027-test-1","args":[[1,1,1],2],"expected":2,"isSample":true},{"id":"ac-027-test-2","args":[[1,2,3],3],"expected":2,"isSample":true},{"id":"ac-027-test-3","args":[[],0],"expected":0,"isSample":false},{"id":"ac-027-test-4","args":[[0,0],0],"expected":3,"isSample":false}],"examples":[{"id":"ac-027-example","input":[[1,1,1],2],"expected":2}],"constraints":[{"zh":"0 <= values.length <= 100000","en":"0 <= values.length <= 100000"}],"hints":{"zh":["区间和可以由两个前缀和相减得到。","当前前缀为 sum 时，需要之前出现过 sum-target。","频次表初始包含前缀和 0 一次。"],"en":["A range sum is the difference of two prefix sums.","At prefix sum, look for prior sum-target occurrences.","Initialize the frequency map with prefix sum 0 once."]},"reviewPoints":[{"zh":"需要保存频次而非仅保存是否出现。","en":"Store frequencies, not just presence."},{"zh":"初始零前缀覆盖从下标 0 开始的区间。","en":"The initial zero prefix covers ranges starting at index 0."}],"estimatedMinutes":22},{"id":"ac-028","slug":"three-value-target","title":{"zh":"三个数能否组成目标和","en":"Three Values for a Target Sum"},"description":{"zh":"判断数组中是否存在三个不同位置的元素之和等于 target。","en":"Determine whether values at three distinct positions sum to target."},"difficulty":"medium","topics":["two-pointers"],"entryPoint":"hasThreeValueTarget","templates":{"javascript":"function hasThreeValueTarget(values, target) {\n  // TODO: implement your solution.\n  \n}","python":"def has_three_value_target(values, target):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-028-test-1","args":[[-1,0,1,2,-1,-4],0],"expected":true,"isSample":true},{"id":"ac-028-test-2","args":[[1,2,4],8],"expected":false,"isSample":true},{"id":"ac-028-test-3","args":[[0,0,0],0],"expected":true,"isSample":false},{"id":"ac-028-test-4","args":[[],0],"expected":false,"isSample":false}],"examples":[{"id":"ac-028-example","input":[[-1,0,1,2,-1,-4],0],"expected":true}],"constraints":[{"zh":"0 <= values.length <= 3000","en":"0 <= values.length <= 3000"}],"hints":{"zh":["排序后先固定其中一个位置。","剩余两个数可用左右指针寻找。","固定 i，在 i+1 与末尾间按当前和移动指针。"],"en":["Sort first, then fix one position.","Use left and right pointers for the remaining pair.","Fix i and move pointers between i+1 and the end based on the sum."]},"reviewPoints":[{"zh":"排序把两数搜索转化为单调移动。","en":"Sorting turns pair search into monotonic movement."},{"zh":"不同位置通过指针边界保证。","en":"Pointer boundaries guarantee distinct positions."}],"estimatedMinutes":22},{"id":"ac-029","slug":"maximum-water-container","title":{"zh":"最大盛水面积","en":"Maximum Water Container"},"description":{"zh":"每个非负整数表示竖线高度，选择两条线返回可围成的最大面积。","en":"Each non-negative integer is a vertical line height; choose two lines for the maximum contained area."},"difficulty":"medium","topics":["two-pointers"],"entryPoint":"maximumContainerArea","templates":{"javascript":"function maximumContainerArea(heights) {\n  // TODO: implement your solution.\n  \n}","python":"def maximum_container_area(heights):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-029-test-1","args":[[1,8,6,2,5,4,8,3,7]],"expected":49,"isSample":true},{"id":"ac-029-test-2","args":[[1,1]],"expected":1,"isSample":true},{"id":"ac-029-test-3","args":[[1]],"expected":0,"isSample":false},{"id":"ac-029-test-4","args":[[4,3,2,1,4]],"expected":16,"isSample":false}],"examples":[{"id":"ac-029-example","input":[1,8,6,2,5,4,8,3,7],"expected":49}],"constraints":[{"zh":"0 <= heights.length <= 100000","en":"0 <= heights.length <= 100000"}],"hints":{"zh":["面积由宽度与较短边共同决定。","从两端开始，移动较短的一侧。","每步更新 min(height[left],height[right])*(right-left)。"],"en":["Area is determined by width and the shorter line.","Start at both ends and move the shorter side.","Update min(height[left],height[right])*(right-left) each step."]},"reviewPoints":[{"zh":"移动较长边无法改善当前高度瓶颈。","en":"Moving the taller side cannot improve the current height bottleneck."},{"zh":"双指针在 O(n) 内覆盖可能的改进。","en":"Two pointers cover possible improvements in O(n)."}],"estimatedMinutes":20},{"id":"ac-030","slug":"remove-adjacent-pairs","title":{"zh":"删除相邻重复字符","en":"Remove Adjacent Duplicate Pairs"},"description":{"zh":"反复删除字符串中相邻且相同的两个字符，返回最终字符串。","en":"Repeatedly remove adjacent equal character pairs and return the final string."},"difficulty":"easy","topics":["stack"],"entryPoint":"removeAdjacentPairs","templates":{"javascript":"function removeAdjacentPairs(text) {\n  // TODO: implement your solution.\n  \n}","python":"def remove_adjacent_pairs(text):\n    # TODO: implement your solution.\n    pass"},"tests":[{"id":"ac-030-test-1","args":["abbaca"],"expected":"ca","isSample":true},{"id":"ac-030-test-2","args":["azxxzy"],"expected":"ay","isSample":true},{"id":"ac-030-test-3","args":[""],"expected":"","isSample":false},{"id":"ac-030-test-4","args":["aaaa"],"expected":"","isSample":false}],"examples":[{"id":"ac-030-example","input":"abbaca","expected":"ca"}],"constraints":[{"zh":"0 <= text.length <= 100000","en":"0 <= text.length <= 100000"}],"hints":{"zh":["删除后新相邻的字符也可能继续匹配。","需要保留尚未被抵消的字符序列。","栈顶等于当前字符就弹出，否则压入。"],"en":["A deletion can create another adjacent match.","Keep the sequence of characters not yet canceled.","Pop when the top equals the current character; otherwise push."]},"reviewPoints":[{"zh":"栈顶代表当前结果的末尾。","en":"The stack top is the end of the current result."},{"zh":"每个字符最多入栈和出栈一次。","en":"Each character is pushed and popped at most once."}],"estimatedMinutes":14}]$catalog$::jsonb) AS problem
),
upserted_problems AS (
  INSERT INTO "algocoach"."coach_problem" (
    "id", "slug", "owner_user_id", "source", "title", "description",
    "difficulty", "topics", "entry_point", "templates", "examples",
    "constraints", "hints", "review_points", "estimated_minutes",
    "status", "content_version", "updated_at"
  )
  SELECT
    problem->>'id',
    problem->>'slug',
    NULL,
    'curated',
    problem->'title',
    problem->'description',
    problem->>'difficulty',
    ARRAY(SELECT jsonb_array_elements_text(problem->'topics')),
    problem->>'entryPoint',
    problem->'templates',
    problem->'examples',
    problem->'constraints',
    problem->'hints',
    problem->'reviewPoints',
    (problem->>'estimatedMinutes')::smallint,
    'published',
    1,
    now()
  FROM catalog
  ON CONFLICT ("id") DO UPDATE SET
    "slug" = EXCLUDED."slug",
    "source" = EXCLUDED."source",
    "title" = EXCLUDED."title",
    "description" = EXCLUDED."description",
    "difficulty" = EXCLUDED."difficulty",
    "topics" = EXCLUDED."topics",
    "entry_point" = EXCLUDED."entry_point",
    "templates" = EXCLUDED."templates",
    "examples" = EXCLUDED."examples",
    "constraints" = EXCLUDED."constraints",
    "hints" = EXCLUDED."hints",
    "review_points" = EXCLUDED."review_points",
    "estimated_minutes" = EXCLUDED."estimated_minutes",
    "status" = EXCLUDED."status",
    "content_version" = EXCLUDED."content_version",
    "updated_at" = now()
  RETURNING "id"
),
catalog_tests AS (
  SELECT
    problem->>'id' AS problem_id,
    test_case,
    (ordinality - 1)::smallint AS ordinal
  FROM catalog
  CROSS JOIN LATERAL jsonb_array_elements(problem->'tests')
    WITH ORDINALITY AS test_rows(test_case, ordinality)
)
INSERT INTO "algocoach"."coach_test_case" (
  "id", "problem_id", "ordinal", "args", "expected", "is_sample",
  "label", "timeout_ms", "updated_at"
)
SELECT
  test_case->>'id',
  problem_id,
  ordinal,
  test_case->'args',
  test_case->'expected',
  COALESCE((test_case->>'isSample')::boolean, false),
  test_case->'label',
  3000,
  now()
FROM catalog_tests
CROSS JOIN (SELECT count(*) FROM upserted_problems) AS seeded
ON CONFLICT ("id") DO UPDATE SET
  "problem_id" = EXCLUDED."problem_id",
  "ordinal" = EXCLUDED."ordinal",
  "args" = EXCLUDED."args",
  "expected" = EXCLUDED."expected",
  "is_sample" = EXCLUDED."is_sample",
  "label" = EXCLUDED."label",
  "timeout_ms" = EXCLUDED."timeout_ms",
  "updated_at" = now();
